const lead = $input.first().json;

// ========================================
// PURAESTATE LEAD SCORING SYSTEM v2
// Max Score: 100 points
// ========================================

let score = 0;
const scoreBreakdown = {};

// --- DEMOGRAPHIC SIGNALS (30 pts max) ---

// Budget indicates seriousness
if (lead.budget >= 5000000) { score += 20; scoreBreakdown.budget = 20; }
else if (lead.budget >= 2000000) { score += 15; scoreBreakdown.budget = 15; }
else if (lead.budget >= 500000) { score += 10; scoreBreakdown.budget = 10; }
else if (lead.budget > 0) { score += 5; scoreBreakdown.budget = 5; }

// Financing readiness
if (lead.financing_type === 'cash') { score += 10; scoreBreakdown.financing = 10; }
else if (lead.financing_type === 'bond_approved') { score += 8; scoreBreakdown.financing = 8; }
else if (lead.financing_type === 'bond_applying') { score += 5; scoreBreakdown.financing = 5; }

// Has phone number (contactable)
if (lead.phone && lead.phone.length > 9) { score += 5; scoreBreakdown.phone = 5; }

// --- INTENT SIGNALS (40 pts max) ---

// Purchase timeline
if (lead.timeline === 'immediate') { score += 20; scoreBreakdown.timeline = 20; }
else if (lead.timeline === '1_3_months') { score += 15; scoreBreakdown.timeline = 15; }
else if (lead.timeline === '3_6_months') { score += 10; scoreBreakdown.timeline = 10; }
else if (lead.timeline === '6_12_months') { score += 5; scoreBreakdown.timeline = 5; }
else if (lead.timeline === 'just_browsing') { score += 1; scoreBreakdown.timeline = 1; }

// Viewing requested = strong intent
if (lead.viewing_requested) { score += 10; scoreBreakdown.viewing_requested = 10; }

// Enquired about specific property = high intent
if (lead.property_id) { score += 10; scoreBreakdown.property_specific = 10; }

// --- BEHAVIORAL SIGNALS (30 pts max) ---

// Property views on site
const propViews = Number(lead.property_views || 0);
if (propViews >= 10) { score += 8; scoreBreakdown.property_views = 8; }
else if (propViews >= 5) { score += 5; scoreBreakdown.property_views = 5; }
else if (propViews >= 2) { score += 3; scoreBreakdown.property_views = 3; }

// Saved properties = serious interest
const saved = Number(lead.saved_properties || 0);
if (saved >= 3) { score += 7; scoreBreakdown.saved = 7; }
else if (saved >= 1) { score += 4; scoreBreakdown.saved = 4; }

// Email engagement
const emailOpens = Number(lead.email_opens || 0);
const emailClicks = Number(lead.email_clicks || 0);
if (emailClicks >= 3) { score += 8; scoreBreakdown.email_engagement = 8; }
else if (emailClicks >= 1) { score += 5; scoreBreakdown.email_engagement = 5; }
else if (emailOpens >= 3) { score += 3; scoreBreakdown.email_engagement = 3; }

// Viewing requests
const viewingReqs = Number(lead.viewing_requests || 0);
if (viewingReqs >= 1) { score += 7; scoreBreakdown.viewing_requests = 7; }

// Recency decay - reduce score if no activity
const lastInteraction = lead.last_interaction ? new Date(lead.last_interaction) : new Date(lead.submitted_at);
const daysSinceActivity = (Date.now() - lastInteraction.getTime()) / (1000 * 60 * 60 * 24);
if (daysSinceActivity > 30) { score = Math.max(0, score - 20); scoreBreakdown.decay = -20; }
else if (daysSinceActivity > 14) { score = Math.max(0, score - 10); scoreBreakdown.decay = -10; }
else if (daysSinceActivity > 7) { score = Math.max(0, score - 5); scoreBreakdown.decay = -5; }

// Cap at 100
score = Math.min(100, Math.max(0, score));

// Determine lead tier
let tier = 'cold';
if (score >= 70) tier = 'hot';
else if (score >= 40) tier = 'warm';

const scoreChanged = score !== Number(lead.current_score);
const becameHot = tier === 'hot' && lead.current_score < 70;

return [{
  json: {
    lead_id: lead.lead_id,
    email: lead.email,
    first_name: lead.first_name,
    last_name: lead.last_name,
    new_score: score,
    old_score: lead.current_score,
    tier,
    score_changed: scoreChanged,
    became_hot: becameHot,
    score_breakdown: JSON.stringify(scoreBreakdown),
    days_since_activity: Math.round(daysSinceActivity)
  }
}];

